12	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type Scenario = { customer: { yearsWithMHPCO: number }; steps: QuoteStep[] };
15	
16	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type];
17	
18	const COMPONENT_BLOCK_SIZE = 3;
19	const COMPONENT_BLOCK_PREMIUM = 60;
20	
21	const groupByType = (items: Item[]): Item[][] => {
22	  const groups = new Map<string, Item[]>();
23	  for (const item of items) {
24	    const group = groups.get(item.type) ?? [];
25	    group.push(item);
26	    groups.set(item.type, group);
27	  }
28	  return [...groups.values()];
29	};
30	
31	const sumOfBasePremiums = (items: Item[]): number =>
32	  items.reduce((sum, item) => sum + basePremiumFor(item), 0);
33	
34	const basePremiumForGroup = (group: Item[]): number =>
35	  group.length === COMPONENT_BLOCK_SIZE
36	    ? COMPONENT_BLOCK_PREMIUM
37	    : sumOfBasePremiums(group);
38	
39	const totalBasePremium = (items: Item[]): number =>
40	  groupByType(items).reduce((sum, group) => sum + basePremiumForGroup(group), 0);
41	
42	const CURSE_SURCHARGE_RATE = 0.5;
43	const HIGH_ENCHANTMENT_RATE = 0.3;
44	const HIGH_ENCHANTMENT_THRESHOLD = 5;
45	const FIRST_INSURANCE_RATE = 0.1;
46	
47	const surchargeOn = (
48	  items: Item[],
49	  applies: (item: Item) => boolean,
50	  rate: number,
51	): number =>
52	  items
53	    .filter(applies)
54	    .reduce((sum, item) => sum + basePremiumFor(item) * rate, 0);
55	
56	const isCursed = (item: Item): boolean => item.cursed === true;
57	const isHighlyEnchanted = (item: Item): boolean =>
58	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
59	
60	const curseSurcharge = (items: Item[]): number =>
61	  surchargeOn(items, isCursed, CURSE_SURCHARGE_RATE);
62	
63	const highEnchantmentSurcharge = (items: Item[]): number =>
64	  surchargeOn(items, isHighlyEnchanted, HIGH_ENCHANTMENT_RATE);
65	
66	const premiumFor = (items: Item[]): number => {
67	  const baseTotal = totalBasePremium(items);
68	  const firstInsuranceSurcharge = baseTotal * FIRST_INSURANCE_RATE;
69	  return Math.ceil(
70	    baseTotal +
71	      curseSurcharge(items) +
72	      highEnchantmentSurcharge(items) +
73	      firstInsuranceSurcharge +
74	      PROCESSING_FEE,
75	  );
76	};
77	
78	const resultFor = (step: QuoteStep) => ({ premium: premiumFor(step.items) });
79	
80	export const runScenario = (input: unknown): unknown => {
81	  const scenario = input as Scenario;
82	  return { results: scenario.steps.map(resultFor) };
83	};
