const CURSE_SURCHARGE_RATE = 0.5;
const HIGH_ENCHANTMENT_RATE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;
const FIRST_INSURANCE_RATE = 0.1;

const isCursed = (item: Item): boolean => item.cursed === true;
const isHighlyEnchanted = (item: Item): boolean =>
  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;

const ITEM_SURCHARGES: { applies: (item: Item) => boolean; rate: number }[] = [
  { applies: isCursed, rate: CURSE_SURCHARGE_RATE },
  { applies: isHighlyEnchanted, rate: HIGH_ENCHANTMENT_RATE },
];

const itemSurchargesFor = (item: Item): number =>
  ITEM_SURCHARGES.reduce(
    (sum, { applies, rate }) => sum + (applies(item) ? basePremiumFor(item) * rate : 0),
    0,
  );

const totalItemSurcharges = (items: Item[]): number =>
  items.reduce((sum, item) => sum + itemSurchargesFor(item), 0);

const premiumFor = (items: Item[]): number => {
  const baseTotal = totalBasePremium(items);
  return Math.ceil(
    baseTotal +
      totalItemSurcharges(items) +
      baseTotal * FIRST_INSURANCE_RATE +
      PROCESSING_FEE,
  );
};
